import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import DataLoader, Dataset
from torchvision import transforms
from torchvision.models import resnet18, ResNet18_Weights
from PIL import Image
import requests
from io import BytesIO
import os

# --- Configuration ---
# You can change these URLs and paths
MODEL_URL = "https://download.pytorch.org/models/resnet18-f37072fd.pth" # Example: ResNet18 weights
LOCAL_MODEL_PATH = "resnet18_pretrained.pth"
NUM_CLASSES_CUSTOM = 2  # Example: binary classification
BATCH_SIZE = 32
LEARNING_RATE = 0.001
NUM_EPOCHS = 5

# --- 1. Download Pretrained Model ---
def download_model(url, save_path):
    if os.path.exists(save_path):
        print(f"Model already exists at {save_path}. Skipping download.")
        return
    print(f"Downloading model from {url}...")
    response = requests.get(url, stream=True)
    response.raise_for_status() # Raise an exception for bad status codes
    with open(save_path, 'wb') as f:
        for chunk in response.iter_content(chunk_size=8192):
            f.write(chunk)
    print(f"Model downloaded to {save_path}")

# --- 2. Define Custom Dataset (Example) ---
# Replace this with your actual custom dataset loading logic
class CustomDataset(Dataset):
    def __init__(self, num_samples=100, transform=None):
        self.num_samples = num_samples
        self.transform = transform
        # Simulate some data and labels
        self.data = [Image.new('RGB', (224, 224), color = (i*2, i*2, i*2)) for i in range(num_samples)]
        self.labels = [i % NUM_CLASSES_CUSTOM for i in range(num_samples)] # 0 or 1 for binary

    def __len__(self):
        return self.num_samples

    def __getitem__(self, idx):
        image = self.data[idx]
        label = self.labels[idx]

        if self.transform:
            image = self.transform(image)
        return image, label

# --- 3. Main Script ---
def main():
    # Set device
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    print(f"Using device: {device}")

    # Step 1: Download the pretrained model
    download_model(MODEL_URL, LOCAL_MODEL_PATH)

    # Step 2: Load the pretrained model
    # Initialize the model with pretrained weights structure
    # This example uses ResNet18
    model = resnet18(weights=None) # Initialize model without default pretrained weights
    
    # Load state_dict from the downloaded file
    # Map to CPU if training on CPU and model was saved with CUDA
    state_dict = torch.load(LOCAL_MODEL_PATH, map_location=device)
    model.load_state_dict(state_dict)
    print(f"Model loaded from {LOCAL_MODEL_PATH}")

    # Step 3: Modify the classifier for fine-tuning
    # For ResNet, the final classification layer is `fc`
    num_ftrs = model.fc.in_features
    model.fc = nn.Linear(num_ftrs, NUM_CLASSES_CUSTOM)
    model = model.to(device)
    print(f"Model's final layer modified for {NUM_CLASSES_CUSTOM} classes.")

    # Step 4: Define data transformations
    # Standard transformations for ImageNet-pretrained models
    transform = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    # Step 5: Create custom dataset and data loaders
    print("Creating custom dataset (example)...")
    train_dataset = CustomDataset(num_samples=100, transform=transform)
    val_dataset = CustomDataset(num_samples=20, transform=transform) # For validation
    train_loader = DataLoader(train_dataset, batch_size=BATCH_SIZE, shuffle=True)
    val_loader = DataLoader(val_dataset, batch_size=BATCH_SIZE, shuffle=False)
    print(f"Train dataset size: {len(train_dataset)}, Validation dataset size: {len(val_dataset)}")

    # Step 6: Define loss function and optimizer
    criterion = nn.CrossEntropyLoss()
    # Fine-tune only the final layer, or all layers with a smaller LR
    # Example: Fine-tune all layers
    optimizer = optim.Adam(model.parameters(), lr=LEARNING_RATE)
    # Example: Freeze all layers except the final one (uncomment below)
    # for param in model.parameters():
    #     param.requires_grad = False
    # model.fc.requires_grad = True
    # optimizer = optim.Adam(model.fc.parameters(), lr=LEARNING_RATE)


    # Step 7: Train the model
    print("\nStarting fine-tuning...")
    best_accuracy = 0.0

    for epoch in range(NUM_EPOCHS):
        model.train() # Set model to training mode
        running_loss = 0.0
        correct_predictions = 0
        total_predictions = 0

        for i, (inputs, labels) in enumerate(train_loader):
            inputs, labels = inputs.to(device), labels.to(device)

            optimizer.zero_grad() # Zero the parameter gradients

            outputs = model(inputs) # Forward pass
            loss = criterion(outputs, labels) # Calculate loss
            loss.backward() # Backward pass
            optimizer.step() # Optimize

            running_loss += loss.item() * inputs.size(0)
            _, predicted = torch.max(outputs.data, 1)
            total_predictions += labels.size(0)
            correct_predictions += (predicted == labels).sum().item()

        epoch_loss = running_loss / len(train_dataset)
        epoch_accuracy = correct_predictions / total_predictions
        print(f"Epoch {epoch+1}/{NUM_EPOCHS}, Train Loss: {epoch_loss:.4f}, Train Accuracy: {epoch_accuracy:.4f}")

        # Step 8: Validate the model (optional but recommended)
        model.eval() # Set model to evaluation mode
        val_loss = 0.0
        val_correct_predictions = 0
        val_total_predictions = 0

        with torch.no_grad(): # Disable gradient calculation for validation
            for inputs, labels in val_loader:
                inputs, labels = inputs.to(device), labels.to(device)
                outputs = model(inputs)
                loss = criterion(outputs, labels)

                val_loss += loss.item() * inputs.size(0)
                _, predicted = torch.max(outputs.data, 1)
                val_total_predictions += labels.size(0)
                val_correct_predictions += (predicted == labels).sum().item()

        val_epoch_loss = val_loss / len(val_dataset)
        val_epoch_accuracy = val_correct_predictions / val_total_predictions
        print(f"Validation Loss: {val_epoch_loss:.4f}, Validation Accuracy: {val_epoch_accuracy:.4f}")

        if val_epoch_accuracy > best_accuracy:
            best_accuracy = val_epoch_accuracy
            # Save the best model checkpoint
            torch.save(model.state_dict(), "best_finetuned_model.pth")
            print("Saved best finetuned model!")

    print("\nFine-tuning complete!")
    print(f"Best validation accuracy: {best_accuracy:.4f}")
    print("Final finetuned model saved as 'best_finetuned_model.pth'")

if __name__ == "__main__":
    main()